
    CREATE TABLE teamLog(
        game_id TEXT,
        game_date TEXT,
        team_id TEXT,
        opp_id TEXT,
        attendance INT,
        home INT,
        inactive TEXT,
        count_inactive INT,
        assist_percentage FLOAT,
        offensive_rating FLOAT,
        defensive_rating FLOAT,
        pace FLOAT,
        possessions INT,
        off_rb_pct FLOAT,
        def_rb_pct FLOAT,
        second_chance_points INT,
        sc_points_allowed INT,
        points_fast_break INT,
        fb_points_allowed,
        points_off_turnovers INT,
        to_points_allowed INT,
        bench_points INT,
        bp_allowed INT,
        biggest_lead INT,
        biggest_deficit INT,
        biggest_run INT,
        biggest_run_allowed INT,
        time_leading TEXT,
        times_tied INT,
        q1_pts INT,
        q2_pts INT,
        q3_pts INT,
        q4_pts INT,
        ot1_pts INT,
        ot2_pts INT,
        ot3_pts INT,
        ot4_pts INT,
        win INT,
        season TEXT,
        PRIMARY KEY (game_id,team_id)
    )